/**
 * idle() — schedule a callback to run when the browser is idle, with a hard
 * deadline. Falls back to setTimeout(0) when requestIdleCallback is not
 * supported (Safari, JSDOM, older WebViews).
 *
 * Used for bookkeeping that must NOT block the next paint:
 *   - replay frame capture
 *   - lifetime stats persistence
 *   - achievement evaluation
 *   - analytics emit
 *
 * Returns an opaque handle that can be passed to cancelIdle().
 *
 * Time complexity: O(1). Space: O(1).
 */
export interface IdleHandle {
  __id: number;
  __kind: 'ric' | 'timeout';
}

interface IdleWindow {
  requestIdleCallback?: (cb: () => void, opts?: { timeout?: number }) => number;
  cancelIdleCallback?: (id: number) => void;
}

export function idle(cb: () => void, timeoutMs = 2000): IdleHandle {
  const w = (typeof window !== 'undefined' ? window : undefined) as
    | (Window & IdleWindow)
    | undefined;
  if (w && typeof w.requestIdleCallback === 'function') {
    const id = w.requestIdleCallback(cb, { timeout: timeoutMs });
    return { __id: id, __kind: 'ric' };
  }
  const id = setTimeout(cb, 0) as unknown as number;
  return { __id: id, __kind: 'timeout' };
}

export function cancelIdle(h: IdleHandle | null | undefined): void {
  if (!h) return;
  const w = (typeof window !== 'undefined' ? window : undefined) as
    | (Window & IdleWindow)
    | undefined;
  if (h.__kind === 'ric' && w && typeof w.cancelIdleCallback === 'function') {
    w.cancelIdleCallback(h.__id);
  } else if (h.__kind === 'timeout') {
    clearTimeout(h.__id);
  }
}
