import type { EtchSize } from './types';

const DAY_TO_SIZE: EtchSize[] = [
  'expert',       // Sun
  'sketch',       // Mon
  'beginner',     // Tue
  'beginner',     // Wed
  'intermediate', // Thu
  'tall',         // Fri
  'expert',       // Sat
];

export function dailyDifficulty(date: Date): EtchSize {
  return DAY_TO_SIZE[date.getDay()]!;
}

export function dateToIso(date: Date): string {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, '0');
  const d = String(date.getDate()).padStart(2, '0');
  return `${y}-${m}-${d}`;
}

/**
 * Deterministic integer seed for a given date (local TZ).
 * scheme: parse YYYY-MM-DD → digit-only string → 32-bit unsigned int via FNV-1a-like mix.
 */
export function dailySeed(date: Date): number {
  const iso = dateToIso(date);
  const digits = iso.replace(/-/g, '');
  const n = Number(digits);
  let h = (n + 0x9E3779B9) >>> 0;
  h = Math.imul(h ^ (h >>> 15), 0x85EBCA77);
  h = Math.imul(h ^ (h >>> 13), 0xC2B2AE3D);
  h = h ^ (h >>> 16);
  return h >>> 0;
}

export function deterministicRng(seed: number): () => number {
  let a = seed | 0;
  return () => {
    a = (a + 0x6D2B79F5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 2 ** 32;
  };
}
