import { computeClues } from './clues';
import { solveBoard } from './solver';
import { makeBoard } from './board';
import type { Clues } from './types';

export function verifyUniqueDeductive(solution: ReadonlyArray<0|1>, w: number, h: number): boolean {
  const b = makeBoard(solution, w, h);
  const r = solveBoard(b);
  return r.solved;
}

export function verifyUnique(clues: Clues, w: number, h: number): boolean {
  // Backtracking solver: try filling row by row with all valid placements, prune by column feasibility.
  // Stop once two solutions are found.
  let count = 0;
  const grid: (0|1)[] = new Array(w * h).fill(0);

  function enumerateRow(rowClues: number[]): (0|1)[][] {
    return enumeratePatterns(rowClues, w);
  }

  function colsValidSoFar(rowsFilled: number): boolean {
    for (let c = 0; c < w; c++) {
      const partialCol: (0|1)[] = [];
      for (let r = 0; r < rowsFilled; r++) partialCol.push(grid[r * w + c]!);
      if (!isPrefixCompatibleWith(partialCol, clues.cols[c]!)) return false;
    }
    return true;
  }

  function recurse(row: number) {
    if (count >= 2) return;
    if (row === h) {
      // Verify all columns fully
      for (let c = 0; c < w; c++) {
        const col: (0|1)[] = [];
        for (let r = 0; r < h; r++) col.push(grid[r * w + c]!);
        if (!arraysEq(runsOf(col), clues.cols[c]!)) return;
      }
      count++;
      return;
    }
    const patterns = enumerateRow(clues.rows[row]!);
    for (const p of patterns) {
      for (let c = 0; c < w; c++) grid[row * w + c] = p[c]!;
      if (colsValidSoFar(row + 1)) recurse(row + 1);
      if (count >= 2) return;
    }
  }

  recurse(0);
  return count === 1;
}

function enumeratePatterns(clues: number[], N: number): (0|1)[][] {
  const results: (0|1)[][] = [];
  const k = clues.length;
  if (k === 1 && clues[0] === 0) {
    results.push(new Array(N).fill(0));
    return results;
  }
  const buf: (0|1)[] = new Array(N).fill(0);

  function recurse(clueIdx: number, start: number) {
    if (clueIdx === k) {
      results.push(buf.slice());
      return;
    }
    const len = clues[clueIdx]!;
    const remaining = clueIdx < k - 1
      ? clues.slice(clueIdx + 1).reduce((s, c) => s + c, 0) + (k - clueIdx - 1)
      : 0;
    const maxStart = N - len - remaining;
    for (let s = start; s <= maxStart; s++) {
      for (let i = start; i < s; i++) buf[i] = 0;
      for (let i = s; i < s + len; i++) buf[i] = 1;
      if (s + len < N) buf[s + len] = 0;
      recurse(clueIdx + 1, s + len + 1);
    }
    // Reset cells from start
    for (let i = start; i < N; i++) buf[i] = 0;
  }

  recurse(0, 0);
  return results;
}

function isPrefixCompatibleWith(partial: (0|1)[], fullClues: number[]): boolean {
  if (fullClues.length === 1 && fullClues[0] === 0) {
    return partial.every(c => c === 0);
  }
  // Build runs from partial
  const runs: number[] = [];
  let cur = 0;
  for (const v of partial) {
    if (v === 1) cur++;
    else if (cur > 0) { runs.push(cur); cur = 0; }
  }
  // If partial ends with a run in progress (cur > 0), it's still open
  const openRun = cur > 0;

  // The prefix can only have completed at most clues.length runs
  if (runs.length > fullClues.length) return false;

  // Check completed runs
  for (let i = 0; i < runs.length - (openRun ? 0 : 0); i++) {
    if (i < runs.length - (openRun ? 1 : 0)) {
      // Completed run i must match clue i exactly
      if (runs[i] !== fullClues[i]) return false;
    }
  }

  // If there's an open run, check it doesn't exceed the current clue
  if (openRun) {
    const ri = runs.length > 0 ? runs.length - 1 : 0;
    const openLen = cur;
    if (ri >= fullClues.length) return false;
    if (openLen > fullClues[ri]!) return false;
  } else if (runs.length > 0) {
    // Last completed run
    const lastIdx = runs.length - 1;
    if (runs[lastIdx] !== fullClues[lastIdx]) return false;
  }

  return true;
}

function runsOf(line: (0|1)[]): number[] {
  const runs: number[] = [];
  let cur = 0;
  for (const v of line) {
    if (v === 1) cur++;
    else if (cur > 0) { runs.push(cur); cur = 0; }
  }
  if (cur > 0) runs.push(cur);
  return runs.length === 0 ? [0] : runs;
}

function arraysEq(a: number[], b: number[]): boolean {
  if (a.length !== b.length) return false;
  for (let i = 0; i < a.length; i++) if (a[i] !== b[i]) return false;
  return true;
}
