import { useEffect, useRef, useState } from 'react';
import { useStore, useGameActions, useGameState } from '../../state/store';
import { bus } from '../../lib/bus';
import { isForgivingWindow } from '../../state/progression';

/**
 * Anti-frustration nudges. Listens to game events and offers a gentle prompt
 * when the player is struggling:
 *
 *   - 3 mistakes in a row on the current puzzle → "Want a free hint?"
 *   - >120s on Easy puzzle with no recent moves → "Stuck? Try a hint."
 *   - 2 reveals/abandons in a row on Easy → "Want something easier?" (only if
 *     the player has access to sketch puzzles, which everyone does)
 *
 * All nudges are dismissable; once dismissed for a given puzzle they don't
 * return. We track per-puzzle state via the gameStartCount (incremented on
 * each newGame) — a fresh game resets every state.
 *
 * Time complexity: O(1) per tick; the timer runs on a 5s interval and is
 * cleared when the game state changes.
 */
type NudgeKind = 'mistakes' | 'stuck' | 'easier' | null;

export function Nudges() {
  const s = useGameState();
  const a = useGameActions();
  void a; // referenced via easier() below
  const [nudge, setNudge] = useState<NudgeKind>(null);
  const dismissedRef = useRef<Set<NudgeKind>>(new Set());
  const lastMoveAtRef = useRef<number>(Date.now());
  const consecutiveFailsRef = useRef<number>(0);
  const lastGameStartRef = useRef<number>(s.gameStartCount);
  const prevMistakesRef = useRef<number>(s.mistakes);

  // Reset per-puzzle state on newGame
  useEffect(() => {
    if (s.gameStartCount !== lastGameStartRef.current) {
      lastGameStartRef.current = s.gameStartCount;
      dismissedRef.current = new Set();
      lastMoveAtRef.current = Date.now();
      prevMistakesRef.current = 0;
      setNudge(null);
    }
  }, [s.gameStartCount]);

  // Watch for new mistakes → reset "last move" timer + check threshold
  useEffect(() => {
    if (s.mistakes > prevMistakesRef.current) {
      // A mistake was just made
      lastMoveAtRef.current = Date.now();
      if (s.mistakes >= 3 && !dismissedRef.current.has('mistakes')) {
        setNudge('mistakes');
      }
    } else if (s.mistakes < prevMistakesRef.current) {
      // Undo cleared a mistake — also counts as a "move"
      lastMoveAtRef.current = Date.now();
    } else if (s.mistakes === prevMistakesRef.current) {
      // Cells changed but no new mistake: a correct move. Update timer below
      // via board-effect.
    }
    prevMistakesRef.current = s.mistakes;
  }, [s.mistakes]);

  // Watch board changes — any cell change resets the stuck timer
  useEffect(() => {
    lastMoveAtRef.current = Date.now();
  }, [s.board]);

  // Periodic check for "stuck": every 5s on Easy / forgiving window
  useEffect(() => {
    if (s.solved || s.revealed) return;
    if (s.size !== 'sketch' && s.size !== 'beginner') return;
    const id = window.setInterval(() => {
      if (dismissedRef.current.has('stuck')) return;
      if (nudge !== null) return;
      const idleMs = Date.now() - lastMoveAtRef.current;
      // Only offer the "stuck" nudge during the forgiving window OR on sketch
      // size puzzles, and only if the player has made at least one move.
      const inForgiving = isForgivingWindow();
      if (inForgiving && idleMs > 120_000) {
        setNudge('stuck');
      }
    }, 5000);
    return () => clearInterval(id);
  }, [s.solved, s.revealed, s.size, nudge]);

  // Watch for reveals/abandons → track consecutive
  useEffect(() => {
    const offReveal = bus.on('puzzleRevealed', ({ size }) => {
      if (size === 'sketch' || size === 'beginner') {
        consecutiveFailsRef.current += 1;
        if (consecutiveFailsRef.current >= 2 && !dismissedRef.current.has('easier')) {
          setNudge('easier');
        }
      }
    });
    const offWin = bus.on('puzzleSolved', () => {
      consecutiveFailsRef.current = 0;
    });
    return () => { offReveal(); offWin(); };
  }, []);

  function dismiss() {
    if (nudge) dismissedRef.current.add(nudge);
    setNudge(null);
  }

  // CTA: trigger a free hint (level 1). We emit on the bus and let the bridge
  // route it through the regular hint pipeline. We do NOT call noteHintUsed
  // ourselves — the hint pipeline already does that on level-3 escalation,
  // and forcing it here would penalize the forgiving window.
  function takeHint() {
    bus.emit('nudgeFreeHint', { reason: nudge ?? 'mistakes' });
    dismiss();
  }

  function easier() {
    dismiss();
    void a.startIntro();
  }

  // Don't render anything if there's no active board (e.g. onboarding showing).
  if (s.board.cells.length === 0) return null;
  if (!nudge) return null;

  if (nudge === 'mistakes') {
    return (
      <div className="etch-nudge" role="status" data-testid="nudge-mistakes" data-tone="encourage">
        <p className="etch-nudge-text">
          A few wrong spots — totally normal. Want a free hint?
        </p>
        <button type="button" className="etch-nudge-cta" onClick={takeHint}>
          Yes, hint
        </button>
        <button
          type="button"
          className="etch-nudge-dismiss"
          onClick={dismiss}
          aria-label="Dismiss"
        >×</button>
      </div>
    );
  }
  if (nudge === 'stuck') {
    return (
      <div className="etch-nudge" role="status" data-testid="nudge-stuck">
        <p className="etch-nudge-text">
          Stuck? A free hint can get you moving again.
        </p>
        <button type="button" className="etch-nudge-cta" onClick={takeHint}>
          Free hint
        </button>
        <button
          type="button"
          className="etch-nudge-dismiss"
          onClick={dismiss}
          aria-label="Dismiss"
        >×</button>
      </div>
    );
  }
  // 'easier'
  return (
    <div className="etch-nudge" role="status" data-testid="nudge-easier">
      <p className="etch-nudge-text">
        Want to try a friendlier 5×5 puzzle instead?
      </p>
      <button type="button" className="etch-nudge-cta" onClick={easier}>
        Easier puzzle
      </button>
      <button
        type="button"
        className="etch-nudge-dismiss"
        onClick={dismiss}
        aria-label="Dismiss"
      >×</button>
    </div>
  );
}

// useStore import is here purely so the bundler doesn't tree-shake the
// re-export side. Actual logic relies on useGameState/useGameActions.
void useStore;
