/**
 * profile.ts — dev-only perf snapshot. Captures cold-load TTI, paint times,
 * and main-bundle execute time using the standard Performance API.
 *
 * Exposed via window.__etch_perf() in development. Production builds drop
 * the window binding via the import.meta.env.DEV check in main.tsx.
 *
 * Time complexity: O(navigationTiming entries). Space: O(1).
 */
export interface PerfSnapshot {
  /** Time from navigationStart to first contentful paint, or null if not yet recorded. */
  fcp: number | null;
  /** Time from navigationStart to largest contentful paint observed. */
  lcp: number | null;
  /** Time from navigationStart to `domContentLoaded` event. */
  dcl: number | null;
  /** Time from navigationStart to the load event. */
  load: number | null;
  /** Time from navigationStart to the moment this snapshot was taken. */
  now: number;
}

let lastLcp = 0;

export function initProfile(): void {
  if (typeof window === 'undefined') return;
  if (typeof PerformanceObserver === 'undefined') return;
  try {
    const po = new PerformanceObserver((list) => {
      for (const e of list.getEntries()) {
        const t = (e as PerformanceEntry & { startTime?: number }).startTime;
        if (typeof t === 'number' && t > lastLcp) lastLcp = t;
      }
    });
    po.observe({ type: 'largest-contentful-paint', buffered: true });
  } catch {
    // observer not supported for this entry type; ignore
  }
}

export function snapshot(): PerfSnapshot {
  const fcp = readPaintMark('first-contentful-paint');
  const nav = readNav();
  return {
    fcp,
    lcp: lastLcp > 0 ? lastLcp : null,
    dcl: nav?.domContentLoadedEventEnd ?? null,
    load: nav?.loadEventEnd ?? null,
    now: performance.now(),
  };
}

function readPaintMark(name: string): number | null {
  try {
    const entries = performance.getEntriesByName(name);
    const first = entries[0];
    if (first) return first.startTime;
  } catch {}
  return null;
}

function readNav(): PerformanceNavigationTiming | null {
  try {
    const entries = performance.getEntriesByType('navigation');
    const first = entries[0] as PerformanceNavigationTiming | undefined;
    return first ?? null;
  } catch {
    return null;
  }
}
