import type { Clues } from './types';

export function computeClues(solution: ReadonlyArray<0 | 1>, w: number, h: number): Clues {
  const rows: number[][] = [];
  for (let r = 0; r < h; r++) {
    rows.push(runsOf(Array.from({ length: w }, (_, i) => solution[r * w + i] as 0 | 1)));
  }
  const cols: number[][] = [];
  for (let c = 0; c < w; c++) {
    const col: (0|1)[] = [];
    for (let r = 0; r < h; r++) col.push(solution[r * w + c] as 0 | 1);
    cols.push(runsOf(col));
  }
  return { rows, cols };
}

function runsOf(line: ReadonlyArray<0 | 1>): number[] {
  const runs: number[] = [];
  let cur = 0;
  for (const v of line) {
    if (v === 1) cur += 1;
    else if (cur > 0) { runs.push(cur); cur = 0; }
  }
  if (cur > 0) runs.push(cur);
  return runs.length === 0 ? [0] : runs;
}

export function runsOfMarks(line: ReadonlyArray<import('./types').Mark>): number[] {
  const runs: number[] = [];
  let cur = 0;
  for (const v of line) {
    if (v === 'fill') cur += 1;
    else if (cur > 0) { runs.push(cur); cur = 0; }
  }
  if (cur > 0) runs.push(cur);
  return runs;
}
