import { useEffect, useState } from 'react';
import { useHintStore } from '../../state/hint-state';
import { useGameState } from '../../state/store';
import { TECHNIQUE_NAMES } from './techniques';
import { GlossaryModal } from './GlossaryModal';
import './hints.css';

export function HintBanner() {
  const { level, info } = useHintStore();
  const s = useGameState();
  const [showGlossary, setShowGlossary] = useState<string | null>(null);

  // Apply/remove level-3 cell highlight imperatively
  useEffect(() => {
    document.querySelectorAll('[data-hint-highlight]').forEach(el => el.removeAttribute('data-hint-highlight'));
    if (level === 3 && info?.cell) {
      const idx = info.cell.row * s.board.cols + info.cell.col;
      const el = document.querySelector(`[data-cell-idx="${idx}"]`);
      if (el) el.setAttribute('data-hint-highlight', 'cell');
    }
  }, [level, info, s.board.cols]);

  if (!info || level === 0) return null;

  const lineName = info.line.kind === 'row'
    ? `row ${info.line.index + 1}`
    : `column ${info.line.index + 1}`;

  const techName = (TECHNIQUE_NAMES[info.technique] ?? info.technique) as string;

  return (
    <>
      <div className="etch-hint-banner" role="status" aria-live="polite">
        <p className="etch-hint-line">Look at {lineName}.</p>
        {level >= 2 && (
          <p className="etch-hint-tech">
            Technique:{' '}
            <button
              className="etch-tech-link"
              onClick={() => setShowGlossary(info.technique)}
            >
              {techName}
            </button>
          </p>
        )}
        {level === 3 && info.cell && (
          <p className="etch-hint-cell">
            Cell at row {info.cell.row + 1}, column {info.cell.col + 1}{' '}
            {info.cell.kind === 'fill' ? 'must be filled' : 'must be empty'}.
          </p>
        )}
        <p className="etch-hint-meta">
          Hint {level}/3 · tap hint again to escalate · any move dismisses
        </p>
      </div>
      {showGlossary && (
        <GlossaryModal initial={showGlossary} onClose={() => setShowGlossary(null)} />
      )}
    </>
  );
}
