/**
 * Idle prefetch: when the current puzzle is ~80% solved, schedule a deferred
 * task (requestIdleCallback when available, otherwise setTimeout) to pre-warm:
 *   - the lazy "WinCelebration" chunk
 *   - the next deterministic daily JSON (if applicable)
 *
 * Skips entirely on slow networks (`connection.effectiveType !== '4g'`) and
 * when the user has data-saver on. We never want to spend the user's metered
 * bytes on speculative prefetches.
 *
 * Idempotent — fires at most once per game. Cost: 0 on the hot path until the
 * threshold triggers, then ~1 fetch and one dynamic import.
 *
 * Time complexity: O(cells) per board observe (only to count fills); the
 * subscription itself is O(1).
 */
import { useStore } from '../../state/store';
import { idle } from '../../lib/idle';

let armed = false;

interface NetConn {
  effectiveType?: string;
  saveData?: boolean;
}

function networkOk(): boolean {
  const conn = (navigator as Navigator & { connection?: NetConn }).connection;
  if (!conn) return true; // unknown — assume fine
  if (conn.saveData === true) return false;
  if (typeof conn.effectiveType === 'string' && conn.effectiveType !== '4g') return false;
  return true;
}

export function initPrefetch() {
  useStore.subscribe((state) => {
    if (armed || state.solved || state.revealed) return;
    const total = state.board.solution.length;
    if (total === 0) return;
    let filledTargets = 0, neededFills = 0;
    for (let i = 0; i < total; i++) {
      if (state.board.solution[i] === 1) {
        neededFills++;
        if (state.board.cells[i] === 'fill') filledTargets++;
      }
    }
    if (neededFills === 0) return;
    const progress = filledTargets / neededFills;
    if (progress < 0.8) return;
    armed = true;
    // No nested RAFs / idle calls inside this callback — one idle task only.
    idle(() => {
      if (!networkOk()) return;
      // Warm the win sheet so it pops instantly once they finish.
      void import('../win/WinCelebration').catch(() => {});
      // For the daily, prefetch tomorrow's JSON.
      try {
        const today = new Date();
        const tomorrow = new Date(today.getFullYear(), today.getMonth(), today.getDate() + 1);
        const iso = tomorrow.toISOString().slice(0, 10);
        void fetch(`./daily/${iso}.json`, { cache: 'force-cache' }).catch(() => {});
      } catch {}
    });
  });
  // Reset arm flag whenever a new game starts.
  useStore.subscribe((s, prev) => {
    if (s.gameStartCount !== prev.gameStartCount) armed = false;
  });
}
