import { dateToIso } from '../../engine';
import { getStreak } from '../../state/streak-store';

interface Props { days?: number; }

/**
 * Compact 14-day streak strip. Each dot = one day; filled when completed,
 * faded otherwise. Today's dot gets a ring. Inline SVG keeps payload tiny.
 *
 * Time: O(days) — days defaults to 14.
 */
export function StreakStrip({ days = 14 }: Props) {
  const streak = getStreak();
  const completed = new Set(streak.completed);
  const today = new Date();

  const items: Array<{ iso: string; done: boolean; isToday: boolean; label: string }> = [];
  for (let i = days - 1; i >= 0; i--) {
    const d = new Date(today);
    d.setDate(today.getDate() - i);
    const iso = dateToIso(d);
    items.push({
      iso,
      done: completed.has(iso),
      isToday: i === 0,
      label: d.toLocaleDateString(undefined, { weekday: 'short', day: 'numeric' }),
    });
  }

  return (
    <div
      className="etch-streak-strip"
      role="group"
      aria-label={`Streak ${streak.current} days, longest ${streak.longest}`}
    >
      {items.map(it => (
        <span
          key={it.iso}
          role="img"
          className="etch-streak-dot"
          data-done={it.done || undefined}
          data-today={it.isToday || undefined}
          aria-label={`${it.label}${it.done ? ', solved' : ''}`}
          title={`${it.label}${it.done ? ' — solved' : ''}`}
        />
      ))}
      <span className="etch-streak-count" aria-hidden="true">
        {streak.current > 0 ? <>🔥 {streak.current}</> : <>·</>}
      </span>
    </div>
  );
}
