import { memo, useEffect, useRef } from 'react';
import { useStore } from '../../state/store';
import { clueCompletion, lineComplete } from './clue-completion';

/**
 * RowClues — vertical strip of clue numbers, one row per board row.
 *
 * Subscribes only to `board` (cells + clues). Hover-driven highlight is
 * applied imperatively in an effect so we don't re-render the whole strip
 * on every pointer move.
 *
 * Time complexity: render is O(rows * clue-length).
 */
function RowCluesImpl() {
  const board = useStore((s) => s.board);
  const lockedRow = useRef<number | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  // Imperative hover highlight: write `data-highlighted` only on the active
  // row clue. Subscribe to hover changes only — board.cells changes still
  // trigger a normal render via the selector above.
  useEffect(() => {
    let prev: HTMLElement | null = null;
    function apply(row: number | null) {
      if (prev) {
        prev.removeAttribute('data-highlighted');
        prev = null;
      }
      if (row === null) return;
      const node = containerRef.current?.querySelector<HTMLElement>(`#row-clue-${row}`);
      if (node) {
        node.setAttribute('data-highlighted', '');
        prev = node;
      }
    }
    function fromHover(h: { row: number; col: number } | null): number | null {
      if (!h) return null;
      if (h.row >= 0) return h.row;
      return null;
    }
    apply(fromHover(useStore.getState().hover));
    let prevRow = fromHover(useStore.getState().hover);
    const unsub = useStore.subscribe((s) => {
      const next = fromHover(s.hover);
      if (next === prevRow) return;
      prevRow = next;
      apply(next);
    });
    return () => {
      unsub();
      apply(null);
    };
  }, []);

  return (
    <div
      ref={containerRef}
      className="etch-row-clues"
      style={{
        gridArea: 'row-clues',
        gridTemplateRows: `repeat(${board.rows}, 1fr)`,
      } as React.CSSProperties}
    >
      {board.clues.rows.map((clues, r) => {
        const cells = board.cells.slice(r * board.cols, r * board.cols + board.cols);
        const done = clueCompletion(clues, cells);
        const allDone = lineComplete(clues, cells);
        const label = clues.join(', ');
        return (
          <button
            key={r}
            type="button"
            id={`row-clue-${r}`}
            className="etch-clue-line etch-row-clue"
            data-line-complete={allDone || undefined}
            aria-label={`Row ${r + 1} clues: ${label}`}
            onMouseEnter={() => useStore.getState().actions.setHover({ row: r, col: -1 })}
            onClick={() => {
              const cur = useStore.getState();
              // Use lockedRow ref, not hover, so onMouseEnter doesn't pre-trip the toggle.
              if (lockedRow.current === r) {
                lockedRow.current = null;
                cur.actions.setHover(null);
              } else {
                lockedRow.current = r;
                cur.actions.setHover({ row: r, col: -1 });
              }
            }}
          >
            {clues.map((d, i) => (
              <span key={i} className="etch-clue-digit" data-clue-done={done[i] || undefined}>
                {d}
              </span>
            ))}
          </button>
        );
      })}
    </div>
  );
}

export const RowClues = memo(RowCluesImpl);
