import type { Mark } from '../../engine';

/**
 * For one line (row or column), determine which clue digits are 'done'
 * based on the player's current cells.
 *
 * Returns a boolean[] where done[i] means clue[i] is satisfied.
 * Time: O(N) per line.
 */
export function clueCompletion(clues: number[], cells: ReadonlyArray<Mark>): boolean[] {
  if (clues.length === 1 && clues[0] === 0) {
    const allEmpty = cells.every(c => c !== 'fill');
    return [allEmpty];
  }
  const runs: number[] = [];
  let cur = 0;
  for (const m of cells) {
    if (m === 'fill') cur++;
    else if (cur > 0) { runs.push(cur); cur = 0; }
  }
  if (cur > 0) runs.push(cur);

  // Mark each clue done if the player's i-th run matches exactly
  const done: boolean[] = clues.map((c, i) => runs[i] === c);
  return done;
}

export function lineComplete(clues: number[], cells: ReadonlyArray<Mark>): boolean {
  const done = clueCompletion(clues, cells);
  return done.length === clues.length && done.every(Boolean);
}
