import { memo, useCallback } from 'react';
import { useStore } from '../../state/store';
import type { Mark } from '../../engine';

/**
 * Cell — one gridcell button.
 *
 * Subscribes to its own mark slice directly from the store. A click on cell
 * `i` invalidates only this Cell's subscription; the other rows × cols − 1
 * Cells stay parked.
 *
 * Hover/peer highlighting is now driven by `data-hover-row` / `data-hover-col`
 * on the board CONTAINER, not on each cell. That moves an O(cols + rows)
 * re-render per pointer move down to O(1) attribute writes.
 *
 * Time complexity: render is O(1) per cell.
 */
interface Props {
  idx: number;
  row: number; col: number;
  rows: number; cols: number;
  isFocused: boolean;
  rowClueId: string;
  colClueId: string;
  onFocus: (row: number, col: number) => void;
}

export const Cell = memo(function Cell(p: Props) {
  // Narrow selector: this Cell re-renders only when its own mark changes.
  const mark = useStore((s) => s.board.cells[p.idx] ?? ('unmarked' as Mark));

  const major5Right = (p.col + 1) % 5 === 0 && p.col + 1 < p.cols;
  const major5Bottom = (p.row + 1) % 5 === 0 && p.row + 1 < p.rows;
  const left = p.col === 0;
  const top = p.row === 0;

  const labelMark =
    mark === 'fill'  ? 'filled' :
    mark === 'cross' ? 'crossed' :
    'empty';

  const onFocus = p.onFocus;
  const handleFocus = useCallback(() => onFocus(p.row, p.col), [onFocus, p.row, p.col]);

  return (
    <button
      type="button"
      role="gridcell"
      aria-rowindex={p.row + 1}
      aria-colindex={p.col + 1}
      aria-label={`Row ${p.row + 1}, column ${p.col + 1}, ${labelMark}`}
      aria-describedby={`${p.rowClueId} ${p.colClueId}`}
      tabIndex={p.isFocused ? 0 : -1}
      data-cell-idx={p.idx}
      data-row={p.row}
      data-col={p.col}
      data-mark={mark}
      data-focus={p.isFocused || undefined}
      data-major-r={major5Right || undefined}
      data-major-b={major5Bottom || undefined}
      data-edge-l={left || undefined}
      data-edge-t={top || undefined}
      className="etch-cell"
      onFocus={handleFocus}
    />
  );
});
