/**
 * Schema migrations for the persisted run blob (`bilko_etch_run_v1`).
 *
 * Every save record carries a numeric `v` field. When the boot loader reads
 * a save and finds an older version it walks a chain of pure step functions
 * v_n -> v_{n+1} until it reaches `CURRENT_VERSION`. If any step throws or
 * the payload is structurally invalid, we discard the save and surface a
 * one-time "save reset" toast through the event bus.
 *
 * The migration ladder MUST be append-only — historical shapes are pinned
 * in tests/state/migrations.test.ts and treated as part of the on-disk
 * contract.
 *
 * Time complexity: each migration step is O(cells) at worst. The whole
 * ladder runs once per boot for one record, so amortized O(N).
 */
import type { EtchMode, EtchSize, Mark } from '../engine';
import { SIZE_DIMS } from '../engine';

export const CURRENT_VERSION = 6;

/**
 * v6 (current). Adds explicit state-machine fields + an unambiguous version
 * marker. This is the shape `loadSave()` returns to the store.
 */
export interface SaveV6 {
  v: 6;
  rows: number;
  cols: number;
  solution: (0 | 1)[];
  cells: Mark[];
  size: EtchSize;
  mode: EtchMode;
  startedAt: number;
  timeMs: number;
  mistakes: number;
  mistakeLimit: number | null;
  softFailed: boolean;
  hintsUsed: number;
  primary: 'fill' | 'cross';
  iso: string;
  /** Monotonic counter for multi-tab conflict detection. Bumped on every
   *  meaningful state change. */
  rev: number;
  /** Tab/session id that last wrote this save — used to detect another tab
   *  having taken over the same run. */
  writerId: string;
}

// Historical shapes — see test/state/migrations.test.ts. We deliberately
// `export` them so the test file can build representative payloads instead
// of duplicating literals.

/** v1 — the pre-v0.6.0 shape (what shipped in v0.5.0 / v0.4.x). */
export interface SaveV1 {
  v: 1;
  rows: number; cols: number;
  solution: (0 | 1)[];
  cells: ('unmarked' | 'fill' | 'cross')[];
  size: EtchSize;
  mode: EtchMode;
  startedAt: number; timeMs: number;
  mistakes: number; mistakeLimit: number | null; softFailed: boolean;
  hintsUsed: number; primary: 'fill' | 'cross';
  iso: string;
}

/** Hypothetical v2 — adds `softFailedAt` (an unused timestamp that we strip). */
interface SaveV2 extends Omit<SaveV1, 'v'> {
  v: 2;
  softFailedAt?: number;
}

/** Hypothetical v3 — wraps `solution`/`cells` in a typed-array marker. We
 *  unwrap back to plain arrays for the engine. */
interface SaveV3 {
  v: 3;
  rows: number; cols: number;
  solution: { type: 'u8'; data: (0 | 1)[] };
  cells: { type: 'mark'; data: ('unmarked' | 'fill' | 'cross')[] };
  size: EtchSize; mode: EtchMode;
  startedAt: number; timeMs: number;
  mistakes: number; mistakeLimit: number | null; softFailed: boolean;
  hintsUsed: number; primary: 'fill' | 'cross';
  iso: string;
}

/** Hypothetical v4 — renamed `mistakeLimit` -> `mistakes_cap`. */
interface SaveV4 {
  v: 4;
  rows: number; cols: number;
  solution: (0 | 1)[];
  cells: ('unmarked' | 'fill' | 'cross')[];
  size: EtchSize; mode: EtchMode;
  startedAt: number; timeMs: number;
  mistakes: number; mistakes_cap: number | null; softFailed: boolean;
  hintsUsed: number; primary: 'fill' | 'cross';
  iso: string;
}

/** v5 — added `rev` but not `writerId`. */
interface SaveV5 {
  v: 5;
  rows: number; cols: number;
  solution: (0 | 1)[];
  cells: ('unmarked' | 'fill' | 'cross')[];
  size: EtchSize; mode: EtchMode;
  startedAt: number; timeMs: number;
  mistakes: number; mistakeLimit: number | null; softFailed: boolean;
  hintsUsed: number; primary: 'fill' | 'cross';
  iso: string;
  rev: number;
}

export type AnySave = SaveV1 | SaveV2 | SaveV3 | SaveV4 | SaveV5 | SaveV6;

const VALID_SIZES: ReadonlySet<EtchSize> = new Set([
  'sketch', 'beginner', 'intermediate', 'tall', 'expert',
]);
const VALID_MODES: ReadonlySet<EtchMode> = new Set(['daily', 'free']);
const VALID_MARKS: ReadonlySet<Mark> = new Set(['unmarked', 'fill', 'cross']);
const VALID_PRIMARY = new Set(['fill', 'cross']);

function isNum(x: unknown): x is number { return typeof x === 'number' && Number.isFinite(x); }
function isNonNegInt(x: unknown): x is number { return isNum(x) && x >= 0 && Number.isInteger(x); }

/**
 * Strict structural check on a *raw* parsed JSON object — enforces shape
 * BEFORE we believe the `v` field. Returns the verified version or `null`
 * if the payload can't be trusted.
 *
 * Time complexity: O(cells). One pass over `solution`/`cells`.
 */
export function detectVersion(raw: unknown): number | null {
  if (!raw || typeof raw !== 'object') return null;
  const r = raw as Record<string, unknown>;
  if (typeof r.v !== 'number') return null;
  // Common base fields that must exist on every known shape
  if (!isNonNegInt(r.rows) || !isNonNegInt(r.cols)) return null;
  if (!VALID_SIZES.has(r.size as EtchSize)) return null;
  if (!VALID_MODES.has(r.mode as EtchMode)) return null;
  if (!VALID_PRIMARY.has(r.primary as string)) return null;
  // Dimension sanity vs. declared size — disallow oversized payloads (defense
  // in depth: prevents quota DoS via crafted localStorage by another origin).
  const dims = SIZE_DIMS[r.size as EtchSize];
  if (r.rows !== dims.h || r.cols !== dims.w) return null;
  if (!isNonNegInt(r.timeMs) || r.timeMs > 24 * 60 * 60 * 1000) return null;
  return r.v;
}

/** v1 -> v2: drop `softFailedAt` if present (forward-compat for a never-shipped column). */
function up1to2(s: SaveV1): SaveV2 {
  return { ...s, v: 2 };
}

/** v2 -> v3: would have wrapped arrays. We DOWN-shape: v3 was a mistake, treat
 *  v2 as the canonical and skip into v4. (The chain is preserved so that any
 *  player still on v3 in the wild can migrate.) */
function up2to3(s: SaveV2): SaveV3 {
  return {
    v: 3,
    rows: s.rows, cols: s.cols,
    solution: { type: 'u8', data: s.solution.slice() },
    cells: { type: 'mark', data: s.cells.slice() },
    size: s.size, mode: s.mode,
    startedAt: s.startedAt, timeMs: s.timeMs,
    mistakes: s.mistakes, mistakeLimit: s.mistakeLimit, softFailed: s.softFailed,
    hintsUsed: s.hintsUsed, primary: s.primary, iso: s.iso,
  };
}

function up3to4(s: SaveV3): SaveV4 {
  return {
    v: 4,
    rows: s.rows, cols: s.cols,
    solution: s.solution.data.slice(),
    cells: s.cells.data.slice(),
    size: s.size, mode: s.mode,
    startedAt: s.startedAt, timeMs: s.timeMs,
    mistakes: s.mistakes,
    mistakes_cap: s.mistakeLimit,
    softFailed: s.softFailed,
    hintsUsed: s.hintsUsed, primary: s.primary, iso: s.iso,
  };
}

function up4to5(s: SaveV4): SaveV5 {
  return {
    v: 5,
    rows: s.rows, cols: s.cols,
    solution: s.solution.slice(),
    cells: s.cells.slice(),
    size: s.size, mode: s.mode,
    startedAt: s.startedAt, timeMs: s.timeMs,
    mistakes: s.mistakes,
    mistakeLimit: s.mistakes_cap,
    softFailed: s.softFailed,
    hintsUsed: s.hintsUsed, primary: s.primary, iso: s.iso,
    rev: 0,
  };
}

function up5to6(s: SaveV5): SaveV6 {
  return {
    v: 6,
    rows: s.rows, cols: s.cols,
    solution: s.solution.slice(),
    cells: s.cells.slice() as Mark[],
    size: s.size, mode: s.mode,
    startedAt: s.startedAt, timeMs: s.timeMs,
    mistakes: s.mistakes,
    mistakeLimit: s.mistakeLimit,
    softFailed: s.softFailed,
    hintsUsed: s.hintsUsed, primary: s.primary, iso: s.iso,
    rev: s.rev,
    writerId: 'migrated',
  };
}

/**
 * Validate that a v6 payload is internally consistent. Throws if any
 * derived invariant is violated (cell count vs. dims, mark vocabulary,
 * negative counters, etc.). Time complexity: O(cells).
 */
function validateV6(s: SaveV6): SaveV6 {
  if (!Array.isArray(s.cells) || !Array.isArray(s.solution)) throw new Error('arrays');
  if (s.cells.length !== s.rows * s.cols) throw new Error('cells length');
  if (s.solution.length !== s.rows * s.cols) throw new Error('solution length');
  for (let i = 0; i < s.cells.length; i++) {
    if (!VALID_MARKS.has(s.cells[i] as Mark)) throw new Error('cell vocab');
  }
  for (let i = 0; i < s.solution.length; i++) {
    const v = s.solution[i];
    if (v !== 0 && v !== 1) throw new Error('solution vocab');
  }
  if (!isNonNegInt(s.mistakes) || s.mistakes > 1000) throw new Error('mistakes');
  if (!isNonNegInt(s.hintsUsed) || s.hintsUsed > 1000) throw new Error('hints');
  if (s.mistakeLimit !== null && !isNonNegInt(s.mistakeLimit)) throw new Error('mistakeLimit');
  return s;
}

/**
 * Migrate any historical save (or raw parsed JSON) to the current shape.
 * Throws on malformed input — callers handle with the toast fallback.
 *
 * Time complexity: O(cells) for one save record.
 */
export function migrate(raw: unknown): SaveV6 {
  const v = detectVersion(raw);
  if (v === null) throw new Error('schema');
  let cur = raw as AnySave;
  if (v === 1) cur = up1to2(cur as SaveV1);
  if ((cur as AnySave).v === 2) cur = up2to3(cur as SaveV2);
  if ((cur as AnySave).v === 3) cur = up3to4(cur as SaveV3);
  if ((cur as AnySave).v === 4) cur = up4to5(cur as SaveV4);
  if ((cur as AnySave).v === 5) cur = up5to6(cur as SaveV5);
  if ((cur as AnySave).v !== 6) throw new Error('migrate target');
  return validateV6(cur as SaveV6);
}

/**
 * Best-effort: parse a raw localStorage string and migrate it.
 * Returns `{ ok: true, save }` on success, `{ ok: false, reason }` on any
 * failure (JSON, schema, quota). The caller decides whether to show the
 * recovery toast — typically only the first time per session.
 *
 * Time complexity: O(input length).
 */
export type LoadResult =
  | { ok: true; save: SaveV6; migratedFrom: number }
  | { ok: false; reason: 'empty' | 'json' | 'schema' | 'migrate' };

export function loadSave(raw: string | null): LoadResult {
  if (!raw) return { ok: false, reason: 'empty' };
  let parsed: unknown;
  try { parsed = JSON.parse(raw); }
  catch { return { ok: false, reason: 'json' }; }
  const v = detectVersion(parsed);
  if (v === null) return { ok: false, reason: 'schema' };
  try {
    const save = migrate(parsed);
    return { ok: true, save, migratedFrom: v };
  } catch {
    return { ok: false, reason: 'migrate' };
  }
}
