import { useEffect, useState } from 'react';
import { bus } from '../../lib/bus';
import './error.css';

/**
 * Banner that surfaces when another tab is editing the same run. We don't
 * try to merge — the player is asked to choose which tab "wins". Dismiss
 * keeps the local copy; "Sync from other tab" reloads, which fires the
 * resume migration with whatever the sibling last wrote.
 *
 * Time complexity: O(1) per render. Only mounts on conflict.
 */
export function MultiTabBanner() {
  const [show, setShow] = useState(false);

  useEffect(() => {
    const off = bus.on('multiTabConflict', () => setShow(true));
    return off;
  }, []);

  if (!show) return null;
  return (
    <div
      className="etch-multitab"
      role="alert"
      aria-live="polite"
      data-testid="multitab-banner"
    >
      <span>This puzzle is also open in another tab.</span>
      <div className="etch-multitab-actions">
        <button
          type="button"
          className="etch-save-toast-close"
          onClick={() => location.reload()}
        >Sync &amp; reload</button>
        <button
          type="button"
          className="etch-save-toast-close"
          aria-label="Dismiss multi-tab warning"
          onClick={() => setShow(false)}
        >Keep this tab</button>
      </div>
    </div>
  );
}
