const KEY = 'bilko_etch_sounds_v1';
let ctx: AudioContext | null = null;

function enabled(): boolean {
  try { return localStorage.getItem(KEY) === '1'; } catch { return false; }
}

function getCtx(): AudioContext | null {
  if (!enabled()) return null;
  if (ctx) return ctx;
  try {
    ctx = new (window.AudioContext || (window as unknown as { webkitAudioContext: typeof AudioContext }).webkitAudioContext)();
    return ctx;
  } catch { return null; }
}

interface ToneSpec { freq: number; durMs: number; type?: OscillatorType; vol?: number; }

function tone(spec: ToneSpec) {
  const c = getCtx();
  if (!c) return;
  const osc = c.createOscillator();
  const gain = c.createGain();
  osc.type = spec.type ?? 'sine';
  osc.frequency.value = spec.freq;
  gain.gain.value = spec.vol ?? 0.04;
  osc.connect(gain);
  gain.connect(c.destination);
  osc.start();
  osc.stop(c.currentTime + spec.durMs / 1000);
}

function chord(freqs: number[], durMs: number) {
  const step = durMs / freqs.length;
  freqs.forEach((f, i) => setTimeout(() => tone({ freq: f, durMs: step }), i * step));
}

export const sound = {
  mark:         () => tone({ freq: 440, durMs: 30 }),
  cross:        () => tone({ freq: 660, durMs: 20 }),
  clueComplete: () => chord([523.25, 659.25, 783.99], 90),
  win:          () => chord([523.25, 659.25, 783.99], 540),
  error:        () => tone({ freq: 180, durMs: 120, type: 'sawtooth', vol: 0.05 }),
  reveal:       () => tone({ freq: 220, durMs: 240 }),
};

export function setSoundsEnabled(on: boolean) {
  try { localStorage.setItem(KEY, on ? '1' : '0'); } catch {}
  if (!on && ctx) { try { ctx.close(); } catch {} ctx = null; }
}

export function isSoundsEnabled(): boolean { return enabled(); }
