import { useState } from 'react';
import { useGameActions } from '../../state/store';
import { setProgression } from '../../state/progression';
import './onboarding.css';

interface Props {
  /** Player taps "Pick a puzzle" — switch to the regular picker. */
  onPickerRequested: () => void;
}

/**
 * Single dominant CTA for brand-new players: "Play your first puzzle".
 *
 * Drops the player straight into a 5×5 hand-crafted intro (smiley). The
 * regular difficulty picker is one tap behind a secondary "Pick a puzzle"
 * link.
 *
 * Visual hierarchy: one big primary button. Everything else is tertiary.
 */
export function OnboardingCTA({ onPickerRequested }: Props) {
  const a = useGameActions();
  const [busy, setBusy] = useState(false);

  async function startIntro() {
    if (busy) return;
    setBusy(true);
    setProgression({ startedIntro: true });
    try {
      await a.startIntro();
    } finally {
      setBusy(false);
    }
  }

  return (
    <div
      className="etch-onboard"
      role="region"
      aria-label="Welcome"
      data-testid="onboarding-cta"
      data-onboarding-screen="1"
    >
      <div className="etch-onboard-card">
        <div className="etch-onboard-art" aria-hidden="true">
          {/* Inviting visual identity: a tiny 5x5 grid preview of the intro */}
          <svg viewBox="0 0 50 50" className="etch-onboard-art-svg">
            {/* Smiley pattern preview, dotted outline */}
            <rect width="50" height="50" rx="6" className="etch-onboard-art-bg" />
            {[
              [1, 0], [3, 0], [1, 1], [3, 1],
              [0, 3], [4, 3],
              [1, 4], [2, 4], [3, 4],
            ].map(([x, y], i) => (
              <rect
                key={i}
                x={(x as number) * 10 + 1}
                y={(y as number) * 10 + 1}
                width="8" height="8" rx="1"
                className="etch-onboard-art-cell"
              />
            ))}
          </svg>
        </div>
        <h2 className="etch-onboard-eyebrow">Welcome to Etch</h2>
        <p className="etch-onboard-tagline">
          Reveal a hidden picture by following the number clues.
        </p>
        <button
          type="button"
          className="etch-onboard-cta"
          onClick={() => void startIntro()}
          disabled={busy}
          data-testid="onboarding-start"
          aria-label="Play your first puzzle"
        >
          {busy ? 'Loading…' : 'Play your first puzzle'}
        </button>
        <p className="etch-onboard-hint">
          A friendly 5×5 to learn the ropes — about a minute.
        </p>
        <button
          type="button"
          className="etch-onboard-skip"
          onClick={onPickerRequested}
          data-testid="onboarding-pick"
        >
          or pick a different puzzle
        </button>
      </div>
    </div>
  );
}
