import { useEffect, useState } from 'react';
import { bus } from '../../lib/bus';

export function LiveRegion() {
  const [msg, setMsg] = useState('');

  useEffect(() => {
    const offs = [
      bus.on('cellMarked', ({ row, col, kind }) => {
        const verb = kind === 'fill' ? 'Filled' : kind === 'cross' ? 'Crossed' : 'Cleared';
        setMsg(`${verb} at row ${row + 1}, column ${col + 1}.`);
      }),
      bus.on('unitCompleted', ({ kind, index }) => {
        setMsg(`${kind === 'row' ? 'Row' : 'Column'} ${index + 1} complete.`);
      }),
      bus.on('puzzleSolved', ({ timeMs, isPersonalBest }) => {
        const m = Math.floor(timeMs / 60_000);
        const s = Math.floor((timeMs % 60_000) / 1000);
        const t = `${m} minute${m !== 1 ? 's' : ''} ${s} second${s !== 1 ? 's' : ''}`;
        setMsg(isPersonalBest ? `Solved in ${t}. Personal best.` : `Solved in ${t}.`);
      }),
      bus.on('puzzleRevealed', () => setMsg('Solution revealed.')),
      bus.on('achievementUnlocked', ({ label }) => setMsg(`Achievement unlocked: ${label}.`)),
    ];
    return () => offs.forEach(off => off());
  }, []);

  return (
    <div
      className="sr-only"
      role="status"
      aria-live="polite"
      aria-atomic="true"
    >
      {msg}
    </div>
  );
}
