/**
 * Mistake visual feedback.
 *
 * Hard mode (mistakeLimit !== null) means a "mistake" is a real wrong fill —
 * the cell that just gained a `fill` mark while solution[i] === 0, OR the cell
 * that just gained a `cross` mark while solution[i] === 1.
 *
 * On every store change we diff against the previous board: if the player just
 * created a new mistake, we apply:
 *   - `data-shake` on the offending cell (CSS keyframe shake + red flash)
 *   - `data-mistake-pulse` on the row/col clue lines so the relevant clue
 *     pulses to direct the player's attention.
 *
 * Time: O(n) per board change, but we early-exit if the mistake count didn't
 * increase, so the common path is O(1).
 */
import { useStore } from '../../state/store';
import type { Board, Mark } from '../../engine';

function findNewMistake(prev: Board, next: Board): { idx: number; row: number; col: number } | null {
  if (prev.cells.length !== next.cells.length) return null;
  for (let i = 0; i < next.cells.length; i++) {
    const before = prev.cells[i] as Mark;
    const after = next.cells[i] as Mark;
    if (before === after) continue;
    if (after === 'fill' && next.solution[i] === 0) {
      return { idx: i, row: Math.floor(i / next.cols), col: i % next.cols };
    }
    if (after === 'cross' && next.solution[i] === 1) {
      return { idx: i, row: Math.floor(i / next.cols), col: i % next.cols };
    }
  }
  return null;
}

let inited = false;
let prevBoard: Board | null = null;
let prevMistakes = 0;

export function initMistakeFeedback() {
  if (inited) return;
  inited = true;
  prevBoard = useStore.getState().board;
  prevMistakes = useStore.getState().mistakes;

  useStore.subscribe(s => {
    const nb = s.board;
    if (!prevBoard || nb === prevBoard) {
      // First subscribe call OR no board change — just sync.
      prevBoard = nb;
      prevMistakes = s.mistakes;
      return;
    }
    if (s.mistakes <= prevMistakes) {
      prevBoard = nb;
      prevMistakes = s.mistakes;
      return;
    }
    const m = findNewMistake(prevBoard, nb);
    prevBoard = nb;
    prevMistakes = s.mistakes;
    if (!m) return;

    const cell = document.querySelector<HTMLElement>(`[data-cell-idx="${m.idx}"]`);
    cell?.setAttribute('data-shake', 'true');
    setTimeout(() => cell?.removeAttribute('data-shake'), 360);

    const rowClue = document.getElementById(`row-clue-${m.row}`);
    const colClue = document.getElementById(`col-clue-${m.col}`);
    rowClue?.setAttribute('data-mistake-pulse', 'true');
    colClue?.setAttribute('data-mistake-pulse', 'true');
    setTimeout(() => {
      rowClue?.removeAttribute('data-mistake-pulse');
      colClue?.removeAttribute('data-mistake-pulse');
    }, 700);
  });
}
