import { mark } from './board';
import type { Board, Coord, CellMarkInput } from './types';

/**
 * Apply the same mark across an ordered path of coords (player drag gesture).
 * No-ops on already-matching cells. Returns one new board with all changes applied.
 */
export function dragMark(b: Board, path: Coord[], kind: CellMarkInput): Board {
  let out = b;
  for (const c of path) out = mark(out, c, kind);
  return out;
}
