/**
 * Multi-tab guard.
 *
 * Detects "same game open in two tabs" via `BroadcastChannel`. The two
 * concrete failure modes we care about are:
 *
 *   1. Double-spent hints — Tab A and Tab B both press "Reveal a cell" on
 *      what is, save-wise, the same run. The shared `hintsUsed` counter
 *      gets double-incremented because both tabs flush to the same key.
 *   2. Double-counted stats — both tabs win the same daily, increment
 *      `puzzlesSolved`, record the same streak.
 *
 * Strategy: every tab generates a random `writerId` at boot. Whenever the
 * store mutates we broadcast `{ kind: 'state', rev, writerId, iso }`. When
 * a tab receives a `state` event whose `writerId` differs from its own AND
 * whose `iso` matches its current run, it raises a "another tab took over"
 * flag — the UI can then show a sync warning.
 *
 * The same channel doubles as a hint-spend echo: when a tab uses a hint
 * it broadcasts `{ kind: 'hintUsed' }` so the receiver can update its
 * local cache without rereading the save.
 *
 * Time complexity: each post is O(1); subscribers each O(1) per message.
 */

import type { EtchMode, EtchSize } from '../engine';

export type MultiTabMessage =
  | { kind: 'state'; writerId: string; rev: number; iso: string; mode: EtchMode; size: EtchSize }
  | { kind: 'hintUsed'; writerId: string; iso: string }
  | { kind: 'newGame'; writerId: string; mode: EtchMode; size: EtchSize; iso: string }
  | { kind: 'ping'; writerId: string }
  | { kind: 'pong'; writerId: string };

const CHANNEL_NAME = 'bilko-etch-multitab';

/** Distinguishes this tab from siblings. Random per page load. */
export const WRITER_ID: string = (() => {
  try {
    if (typeof crypto !== 'undefined' && 'randomUUID' in crypto) return (crypto as Crypto).randomUUID();
  } catch { /* fallthrough */ }
  return 'w-' + Math.random().toString(36).slice(2, 10) + '-' + Date.now().toString(36);
})();

type Listener = (msg: MultiTabMessage) => void;

let channel: BroadcastChannel | null = null;
const listeners = new Set<Listener>();

function getChannel(): BroadcastChannel | null {
  if (channel) return channel;
  if (typeof BroadcastChannel === 'undefined') return null;
  try {
    channel = new BroadcastChannel(CHANNEL_NAME);
    channel.onmessage = (e: MessageEvent<MultiTabMessage>) => {
      // Ignore our own echoes (BroadcastChannel doesn't echo by default but
      // we still want a belt-and-braces guard for tests that share an instance).
      if (!e.data || e.data.writerId === WRITER_ID) return;
      for (const l of listeners) l(e.data);
    };
  } catch { channel = null; }
  return channel;
}

export function postMultiTab(msg: MultiTabMessage): void {
  const ch = getChannel();
  if (!ch) return;
  try { ch.postMessage(msg); } catch { /* channel closed */ }
}

export function onMultiTab(fn: Listener): () => void {
  getChannel();
  listeners.add(fn);
  return () => { listeners.delete(fn); };
}

/**
 * Send a one-shot ping at boot. Any tab already running responds with a
 * pong; if we receive one within `timeoutMs`, the caller knows another
 * Etch tab is live and can show a "this game is also open in another tab"
 * banner.
 *
 * Time complexity: O(1) work, plus a single setTimeout.
 */
export function probeOtherTabs(timeoutMs = 250): Promise<boolean> {
  return new Promise(resolve => {
    let seenOther = false;
    const off = onMultiTab(msg => {
      if (msg.kind === 'pong' || msg.kind === 'state') seenOther = true;
    });
    postMultiTab({ kind: 'ping', writerId: WRITER_ID });
    setTimeout(() => { off(); resolve(seenOther); }, timeoutMs);
  });
}

/** Tear-down hook for tests / hot reloads. */
export function _resetMultiTab(): void {
  listeners.clear();
  if (channel) { try { channel.close(); } catch { /* noop */ } }
  channel = null;
}
